    33→<body>
    34→<section id="startScreen">
    35→  <div class="start-card">
    36→    <h1>Caso clinico</h1>
    37→    <p>Diseñado por Adriel Pereira estudiante de medicina universidad del Zulia.</p>
    38→    <button class="continue" id="beginCase">Continuar</button>
    39→  </div>
    40→</section>
