    42→<div id="app">
    43→  <header class="topbar"><div class="topbar-inner"><div class="topbar-title">H-CR v3</div><div class="topbar-meta">Simulación clínica y adquisición de datos</div><div class="topbar-spacer"></div><button class="small-btn" id="togglePad">Minimizar Pad diagnóstico</button></div></header>
    44→  <nav class="tabs" id="tabs"></nav>
    45→  <div id="workspace">
    46→    <main id="modules"></main>
    47→    <aside class="card pad" id="pad">
    48→      <div class="pad-header"><h2>Pad diagnóstico</h2><button class="pad-toggle" id="padSideBtn">−</button></div>
    49→      <div class="pad-body">
    50→        <div class="pad-meta"><span class="badge" id="timeBadge">Módulo 1</span><span class="badge" id="selectedBadge">0 datos</span></div>
    51→        <div id="padGroups"></div>
    52→        <h3>Enfermedad actual</h3><div class="pad-note" id="padIllness">Pendiente</div>
    53→        <h3>Diagnóstico sindromático</h3><div class="pad-note" id="padSyndrome">Pendiente</div>
    54→        <h3>Tier 3 actual</h3><div class="pad-note" id="padTier">Pendiente</div>
    55→      </div>
    56→    </aside>
