    60→<script>
    61→const STORAGE='hcr_v3_cardiac_hidden_v2';
    62→const sourceOrder=['Triage','Interrogatorio / anamnesis','Historial','Examen funcional','Examen físico','Paraclínicos'];
    63→const state=JSON.parse(localStorage.getItem(STORAGE)||'null')||{started:false,current:'m1',selected:{},fields:{},expanded:{},venn:{placed:{},dx:['','','']},expert:null};
    64→function save(){localStorage.setItem(STORAGE,JSON.stringify(state));}
    65→function esc(s){return String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]));}
    66→function selectedCount(){return Object.keys(state.selected).length}
    67→function selectFinding(id,source,text,checked){if(checked) state.selected[id]={id,source,text}; else {delete state.selected[id]; delete state.venn.placed[id];}save();renderPad();if(state.current==='m5')renderVenn();}
    68→function isSelected(id){return !!state.selected[id]}
    69→function choice(id,source,text,hint=''){return `<label class="selectable ${isSelected(id)?'selected':''}"><input class="finding-check" type="checkbox" data-id="${esc(id)}" data-source="${esc(source)}" data-text="${esc(text)}" ${isSelected(id)?'checked':''}><span class="fact-label">${esc(text)}${hint?`<span class="fact-hint">${esc(hint)}</span>`:''}</span></label>`}
    70→function markExpanded(id,open){state.expanded[id]=open;save();}
    71→function patientBlock(id,source,doctor,patient,deeper=''){return `<div class="dialogue"><div class="doctor">Médico: ${esc(doctor)}</div><details class="patient-details" ${state.expanded[id]?'open':''} ontoggle="markExpanded('${id}',this.open)"><summary><input class="patient-check finding-check" type="checkbox" data-id="${esc(id)}" data-source="${esc(source)}" data-text="${esc(patient)}" ${isSelected(id)?'checked':''} onclick="event.stopPropagation()"><span class="patient-text"><b>Paciente:</b> ${esc(patient)}</span></summary>${deeper?`<div class="deeper">${deeper}</div>`:''}</details></div>`}
    72→function prevCard(previousKey,targetKey){const v=state.fields[previousKey]||'';return `<div class="guidance"><b>Versión anterior visible:</b> ${v?esc(v):'Aún no existe una versión previa.'}<br>${v?`<button class="copy-prev" onclick="copyField('${previousKey}','${targetKey}')">Usar esta versión como base</button>`:''}</div>`}
    73→function field(key,title,instruction,placeholder='',area=true){const val=state.fields[key]||'';return `<div class="field"><div class="field-title">${esc(title)}</div><div class="field-instruction">${esc(instruction)}</div>${area?`<textarea id="${key}" placeholder="${esc(placeholder)}" oninput="setField('${key}',this.value)">${esc(val)}</textarea>`:`<input id="${key}" value="${esc(val)}" placeholder="${esc(placeholder)}" oninput="setField('${key}',this.value)">`}</div>`}
    74→function setField(key,val){state.fields[key]=val;save();renderPad();renderEvaluationStudent();}
    75→function copyField(from,to){state.fields[to]=state.fields[from]||'';save();const el=document.getElementById(to);if(el)el.value=state.fields[to];renderPad();}
    76→function tier(phase){const p={m1:['iniciales','m1'],m2:['actualizados tras el historial','m2'],m3:['actualizados tras el examen físico','m3'],m4:['finales tras paraclínicos','m4']}[phase]; const labels=[['Diagnóstico principal','El diagnóstico que mejor explica los datos disponibles.'],['Diagnóstico secundario','La alternativa razonable o mejor imitador.'],['Diagnóstico fatal que no puedo perder','La amenaza grave que debes mantener abierta.']]; return `<h3>Tier 3 diagnósticos ${p[0]}</h3><div class="tier-grid">${labels.map((x,i)=>`<div class="tier-card"><h4>${x[0]}</h4><p>${x[1]}</p><input placeholder="Nombre del diagnóstico" value="${esc(state.fields[`tier_${p[1]}_${i+1}`]||'')}" oninput="setField('tier_${p[1]}_${i+1}',this.value)"><textarea placeholder="Explica en una frase qué datos lo sostienen." oninput="setField('tier_${p[1]}_${i+1}_why',this.value)">${esc(state.fields[`tier_${p[1]}_${i+1}_why`]||'')}</textarea></div>`).join('')}</div>`}
    77→function phaseClose(phase){const cfg={m1:{ill:'ill_m1',title:'Enfermedad actual de triage',ins:'Redacta una síntesis clínica utilizando exclusivamente los datos que seleccionaste en Triage e Interrogatorio / anamnesis.',prev:null,synd:false},m2:{ill:'ill_m2',title:'Enfermedad actual actualizada tras el historial',ins:'Reformula la síntesis incorporando solamente los datos del Historial y Examen funcional que cambian el problema.',prev:'ill_m1',synd:true},m3:{ill:'ill_m3',title:'Enfermedad actual actualizada tras el examen físico',ins:'Reformula la síntesis con los datos seleccionados durante el examen físico.',prev:'ill_m2',synd:true},m4:{ill:'ill_m4',title:'Enfermedad actual actualizada tras los paraclínicos',ins:'Reformula la síntesis final con los estudios que cambian tu interpretación clínica.',prev:'ill_m3',synd:true}}[phase];return `<div class="card">${cfg.prev?prevCard(cfg.prev,cfg.ill):''}${field(cfg.ill,cfg.title,cfg.ins,'Ej.: Adulto… con evolución… caracterizado por… en contexto de… con…')}${cfg.synd?field('syndrome_'+phase,'Diagnóstico sindromático','Escribe el síndrome construido con los hallazgos disponibles. No escribas una etiología.','Ej.: Síndrome de insuficiencia cardiaca aguda descompensada.',false):''}${tier(phase)}</div>`}
    78→function renderM1(){return `<section class="module active"><div class="module-intro"><h1>Módulo 1 — Triage e interrogatorio / anamnesis</h1><p>Selecciona únicamente los datos que consideres clínicamente útiles. Las respuestas del paciente pueden desplegarse para profundizar.</p></div><div class="m1-grid"><div class="card triage-panel"><h2>Triage</h2><div class="patient-identity"><b>Paciente:</b> Carlos Méndez</div><p class="subtle">Datos generales disponibles al ingreso.</p><div>${[
    79→['t01','Edad: 67 años'],['t02','Sexo: masculino'],['t03','Procedencia: domicilio urbano'],['t04','Motivo referido en admisión: “me está faltando el aire”'],['t05','Temperatura: 36,8 °C'],['t06','PA: 166/94 mmHg'],['t07','FC: 112 lpm'],['t08','FR: 26 rpm'],['t09','SatO₂: 90% al aire ambiente'],['t10','Estado mental: despierto, responde adecuadamente'],['t11','Llega acompañado por una hija'],['t12','Hora de llegada: 19:40']
    80→].map(x=>choice(x[0],'Triage',x[1])).join('')}</div></div><div class="card conversation-panel"><h2>Interrogatorio / anamnesis</h2><p class="subtle">Usa la flecha de cada respuesta para profundizar. Marca la respuesta del paciente cuando quieras conservarla en tu Pad diagnóstico.</p>${patientBlock('i01','Interrogatorio / anamnesis','¿Qué le está pasando hoy?','Desde hace unos días siento que el aire no me alcanza.', patientBlock('i01a','Interrogatorio / anamnesis','¿Cuándo nota más esa falta de aire?','Cuando me acuesto se pone peor; tengo que dormir casi sentado.', patientBlock('i01b','Interrogatorio / anamnesis','¿Se despierta por la noche por esa sensación?','Sí, ya van dos noches que me despierto y tengo que sentarme un rato para calmarme.')))}${patientBlock('i02','Interrogatorio / anamnesis','¿Ha notado algo más además de eso?','Los zapatos me quedan más apretados y los tobillos se me ven hinchados al final del día.',patientBlock('i02a','Interrogatorio / anamnesis','¿Eso de los tobillos ocurre solo de un lado o de los dos?','De los dos, aunque a veces el derecho se me ve un poquito peor.'))}${patientBlock('i03','Interrogatorio / anamnesis','¿Tiene dolor o presión en el pecho ahora mismo?','No, dolor fuerte no tengo. A veces siento el pecho pesado cuando me falta mucho el aire.')}${patientBlock('i04','Interrogatorio / anamnesis','¿Ha tenido fiebre, escalofríos o se ha sentido engripado?','No, no he tenido fiebre ni escalofríos.')}${patientBlock('i05','Interrogatorio / anamnesis','¿Ha tosido?','Sí, una tos seca de vez en cuando; no he sacado flema amarilla ni sangre.')}${patientBlock('i06','Interrogatorio / anamnesis','¿Ha sentido que el corazón le corre o late raro?','A ratos lo siento más rápido, sobre todo cuando camino al baño.')}${patientBlock('i07','Interrogatorio / anamnesis','¿Ha viajado mucho o ha pasado días sin caminar?','No. Esta semana estuve casi siempre en la casa viendo televisión.')}${patientBlock('i08','Interrogatorio / anamnesis','¿Ha cambiado a...
    81→function renderM2(){const hist=(title,body)=>`<details class="accordion"><summary>${title}</summary><div class="accordion-body">${body}</div></details>`;return `<section class="module active"><div class="module-intro"><h1>Módulo 2 — Historial – Examen funcional subjetivo</h1><p>Explora los apartados que consideres pertinentes. Los datos incluyen positivos, negativos y distractores propios de este paciente.</p></div><div class="card"><h2>Historial</h2>${hist('Antecedentes personales y patológicos',[
    82→['h01','Hipertensión arterial conocida desde hace más de 15 años'],['h02','Diabetes mellitus tipo 2 conocida'],['h03','Niega infarto, angioplastia o cirugía cardiaca previa'],['h04','No conoce enfermedad renal previa'],['h05','Niega asma, EPOC o uso de inhaladores'],['h06','Una hospitalización por “falta de aire” hace aproximadamente dos años'],['h07','Niega neumonía o infección respiratoria reciente'],['h08','Antecedente de cirugía de hernia inguinal hace 20 años']
    83→].map(x=>choice(x[0],'Historial',x[1])).join(''))}${hist('Medicamentos',[
